parameters.jsCode:
const emailItem = $('Gmail Trigger').item.json;
const rawContent = $input.first().json.choices[0].message.content.trim();

let triage;
try {
  triage = JSON.parse(rawContent);
} catch (e) {
  throw new Error('MALFORMED_AI_JSON: ' + rawContent);
}

const validCategories = ['new_inquiry', 'client_support', 'billing', 'escalation'];
const validPriorities = ['critical', 'high', 'medium', 'low'];
const validRoutes = ['sales', 'account_manager', 'admin'];

if (!validCategories.includes(triage.category)) throw new Error('INVALID_CATEGORY: ' + triage.category);
if (!validPriorities.includes(triage.priority)) throw new Error('INVALID_PRIORITY: ' + triage.priority);
if (!validRoutes.includes(triage.route_to)) throw new Error('INVALID_ROUTE: ' + triage.route_to);

const fromAddr = emailItem.from?.value?.[0]?.address || emailItem.from?.text || '';
const fromName = emailItem.from?.value?.[0]?.name || fromAddr.split('@')[0];
const nameParts = fromName.trim().split(' ');

return [{
  json: {
    sender_email: fromAddr,
    sender_name: fromName,
    sender_first_name: nameParts[0] || '',
    sender_last_name: nameParts.slice(1).join(' ') || '',
    subject: emailItem.subject || '(no subject)',
    body: emailItem.text || emailItem.snippet || '',
    timestamp: new Date().toISOString(),
    category: triage.category,
    priority: triage.priority,
    summary: triage.summary,
    route_to: triage.route_to
  }
}];

