const category = $input.first().json.category;

const docMap = {
  billing: '1Z396LRKYmC1ENInWY-X946U3NL5igobQ2-yhjrJo2n4',
  escalation: '1thH0AsJQaDpaTo9JgNhXbN6YUlrYZk6WKcu5WFm4aJ4',
  client_support: '1thH0AsJQaDpaTo9JgNhXbN6YUlrYZk6WKcu5WFm4aJ4'
};

const fileId = docMap[category] || null;

return [{
  json: {
    ...$input.first().json,
    selected_file_id: fileId,
    doc_fallback: fileId === null
  }
}];

const item = $input.first().json;
// Google Drive download returns binary data — text is in $binary or data field
// For exported Google Docs (text/plain), content may be in item.data or needs binary read
let docContent = 'Documentation not found — please draft this response manually referencing your internal SOPs.';

if (item.data) {
  docContent = Buffer.from(item.data, 'base64').toString('utf8');
} else if (item.text) {
  docContent = item.text;
}

// Pull triage data from Parse AI Response node
const triage = $('Parse AI Response').item.json;

return [{
  json: {
    sender_email: triage.sender_email,
    sender_name: triage.sender_name,
    sender_first_name: triage.sender_first_name,
    sender_last_name: triage.sender_last_name,
    subject: triage.subject,
    body: triage.body,
    timestamp: triage.timestamp,
    category: triage.category,
    priority: triage.priority,
    summary: triage.summary,
    route_to: triage.route_to,
    doc_content: docContent.substring(0, 8000)  // cap at 8k chars for context window
  }
}];

const draftText = $input.first().json.choices[0].message.content;
const triage = $('Prepare Doc Content').item.json;

return [{
  json: {
    ...triage,
    draft_text: draftText
  }
}];

const hsResponse = $input.first().json;
const triage = $('Extract Draft Text').item.json;

let contactId = null;
let portalId = 'YOUR_PORTAL_ID'; // Replace with your HubSpot portal ID

if (hsResponse.results && hsResponse.results.length > 0) {
  contactId = hsResponse.results[0].id;
}

return [{
  json: {
    ...triage,
    contact_id: contactId,
    contact_exists: contactId !== null,
    portal_id: portalId
  }
}];

